To write unit tests for the `deep_get` function using the `pytest` framework, we will cover various scenarios including happy paths, edge cases, and error cases. Below is a set of tests that you can use:

```python
import pytest

# Assuming the deep_get function is defined in a module named my_module
# from my_module import deep_get

def deep_get(d: dict, keys: str, default=None):
    """Get nested dict value by dot-separated keys."""
    for key in keys.split('.'):
        if isinstance(d, dict):
            d = d.get(key, default)
        else:
            return default
    return d

def test_deep_get_happy_path():
    data = {
        'a': {
            'b': {
                'c': 'value'
            }
        }
    }
    assert deep_get(data, 'a.b.c') == 'value'
    assert deep_get(data, 'a.b') == {'c': 'value'}
    assert deep_get(data, 'a') == {'b': {'c': 'value'}}

def test_deep_get_with_default():
    data = {
        'a': {
            'b': {
                'c': 'value'
            }
        }
    }
    assert deep_get(data, 'a.b.d', default='default_value') == 'default_value'
    assert deep_get(data, 'x.y.z', default='default_value') == 'default_value'

def test_deep_get_empty_dict():
    data = {}
    assert deep_get(data, 'a.b.c', default='default_value') == 'default_value'
    assert deep_get(data, 'a', default='default_value') == 'default_value'

def test_deep_get_non_dict():
    data = 'not_a_dict'
    assert deep_get(data, 'a.b.c', default='default_value') == 'default_value'

def test_deep_get_edge_cases():
    data = {
        'a': {
            'b': None
        }
    }
    assert deep_get(data, 'a.b.c', default='default_value') == 'default_value'
    assert deep_get(data, 'a.b', default='default_value') is None

def test_deep_get_nested_empty_dict():
    data = {
        'a': {
            'b': {}
        }
    }
    assert deep_get(data, 'a.b.c', default='default_value') == 'default_value'
    assert deep_get(data, 'a.b', default='default_value') == {}

def test_deep_get_multiple_levels():
    data = {
        'level1': {
            'level2': {
                'level3': {
                    'level4': 'deep_value'
                }
            }
        }
    }
    assert deep_get(data, 'level1.level2.level3.level4') == 'deep_value'
    assert deep_get(data, 'level1.level2.level3', default='default_value') == {'level4': 'deep_value'}

def test_deep_get_invalid_key_type():
    data = {
        'a': {
            'b': {
                'c': 'value'
            }
        }
    }
    with pytest.raises(TypeError):
        deep_get(data, None)  # Passing None as keys should raise an error
    with pytest.raises(TypeError):
        deep_get(data, 123)  # Passing an integer as keys should raise an error

if __name__ == "__main__":
    pytest.main()
```

### Explanation of the Tests:
1. **Happy Path Tests**: These tests check if the function correctly retrieves values from a nested dictionary when valid keys are provided.
2. **Default Value Tests**: These tests check if the function returns the specified default value when the key path does not exist.
3. **Empty Dictionary Tests**: These tests check the behavior of the function when the input dictionary is empty.
4. **Non-Dict Input Tests**: These tests check how the function behaves when the input is not a dictionary.
5. **Edge Case Tests**: These tests check how the function handles cases where a key exists but its value is `None` or an empty dictionary.
6. **Multiple Levels Tests**: These tests check if the function can handle deeply nested structures correctly.
7. **Invalid Key Type Tests**: These tests check if the function raises a `TypeError` when the keys argument is not a string.

You can run these tests using `pytest` to ensure that the `deep_get` function behaves as expected in various scenarios.
